_type}}</strong><em>Actor #{{$e->actor_id?:'system'}} · {{$e->description}}</em></div>@endforeach</section><section class="panel"><span>ACCESS EVENTS</span><h2>Lifecycle audit</h2>@foreach($accessEvents as $e)<div class="row"><strong>{{$e->event_type}}</strong><em>User #{{$e->user_id}} · {{$e->description}}</em></div>@endforeach</section></section></main><style>.gov{color:#eaf4ff;display:grid;gap:14px}.gov header,.panel,.kpis article{background:#071725;border:1px solid #20384b;border-radius:8px;padding:16px}.gov span{color:#55e6b2;font-size:11px;font-weight:800}.gov h1{font-size:30px;margin:5px 0}.gov p,.gov em{color:#94abc1}.kpis{display:grid;grid-template-columns:repeat(6,1fr);gap:10px}.kpis strong{display:block;font-size:18px;margin-top:7px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.row{display:flex;justify-content:space-between;gap:15px;padding:11px 0;border-bottom:1px solid #20384b}.row div:first-child{display:grid}.gov button,.gov input{background:#0b2937;border:1px solid #286078;border-radius:6px;color:#eaffff;padding:9px}.gov label{display:grid;gap:5px;max-width:600px;color:#9db2c7}@media(max-width:850px){.kpis,.grid{grid-template-columns:1fr 1fr}.row{display:block}.row button{margin-top:8px}}</style></x-filament-panels::page>
